using System;using System.Collections.Generic;using System.Linq;class A{static int n,r=9999;static int[,]O;static List<string>S=new();static void F(int m,int l,int c){if(m==(1<<n)-1){r=Math.Min(r,c);return;}for(int j=0;j<n;j++)if((m>>j&1)==0)F(m|1<<j,j,c+S[j].Length-O[l,j]);}static void Main(){int N=int.Parse(Console.ReadLine());var T=new string[N];for(int i=0;i<N;i++)T[i]=Console.ReadLine();foreach(var x in T)if(!T.Any(t=>t!=x&&t.Contains(x)))S.Add(x);n=S.Count;if(n<2){Console.Write(n>0?S[0].Length:0);return;}O=new int[n,n];for(int i=0;i<n;i++)for(int j=0;j<n;j++)if(i!=j)for(int k=1;k<=Math.Min(S[i].Length,S[j].Length);k++)if(S[i].EndsWith(S[j][..k]))O[i,j]=k;for(int i=0;i<n;i++)F(1<<i,i,S[i].Length);Console.Write(r);}}